791	/* ═══════════ 스토어-R2: 레지스트리 (추가만 — 기존 규칙 미변경) ═══════════ */
792	/* 스토어 카드 출처 칩: registry 출처(📚 owner/repo @rev7) vs 은은한 "번들" */
793	.src-chip {
794	  display: inline-flex; align-items: center; gap: 4px;
795	  font-size: 11px; font-weight: 600; line-height: 1;
796	  padding: 3px 8px; border-radius: 999px; white-space: nowrap;
797	}
798	.src-chip.registry { color: var(--color-primary); background: color-mix(in srgb, var(--color-primary) 12%, transparent); }
799	.src-chip .src-rev { font-family: ui-monospace, Menlo, monospace; font-size: 10px; font-weight: 500; opacity: 0.8; }
800	.src-chip.bundled { color: var(--st-muted); background: transparent; font-weight: 400; padding: 3px 2px; }
801	
802	/* ═══════════ SKC2: 스토어 퍼블리셔 카드 그리드 (추가만 — 기존 규칙 미변경) ═══════════ */
803	/* 퍼블리셔 카드 그리드 — 목업 느낌(카드 hover·리프트, Apple DS 토큰) */
804	.pub-grid {
805	  display: grid; grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
806	  gap: 14px; margin-bottom: 8px;
807	}
808	.pub-card {
809	  display: flex; align-items: center; gap: 13px; text-align: left;
810	  background: var(--color-canvas); border: 1px solid var(--color-hairline);
811	  border-radius: var(--radius-lg); padding: 16px 18px; cursor: pointer; width: 100%;
812	  transition: transform var(--duration-fast) var(--ease-standard),
813	    border-color var(--duration-fast), box-shadow var(--duration-fast);
814	}
815	.pub-card:hover {
816	  border-color: color-mix(in srgb, var(--color-ink) 16%, transparent);
817	  box-shadow: 0 4px 16px color-mix(in srgb, var(--color-ink) 7%, transparent);
818	  transform: translateY(-1px);
819	}
820	.pub-card:active { transform: var(--press-scale); }
821	.pub-ic {
822	  flex: none; font-size: 22px; width: 44px; height: 44px; border-radius: 12px;
823	  display: inline-flex; align-items: center; justify-content: center;
824	  background: var(--color-canvas-parchment);
825	}
826	.pub-body { display: flex; flex-direction: column; gap: 3px; min-width: 0; }
827	.pub-name {
828	  font-size: 15px; font-weight: 600; letter-spacing: -0.2px; color: var(--color-ink);
829	  white-space: nowrap; overflow: hidden; text-overflow: ellipsis;
830	}
831	.pub-meta { font-size: 12.5px; color: var(--st-muted); }
832	.pub-num { font-weight: 600; color: var(--color-ink); }
833	/* 스냅샷(예상) 값은 은은한 톤 + "예상" 뉘앙스로 실제값과 시각 구분 */
834	.pub-num.est { font-weight: 600; color: var(--st-muted); }
835	.pub-est-note { font-size: 11px; color: var(--st-muted); font-style: italic; opacity: 0.85; }
836	
837	/* 드릴다운 상단 바 ([← 전체] + 제목 + 요약) */
838	.pub-drill-bar { display: flex; align-items: center; gap: 12px; margin-bottom: 14px; flex-wrap: wrap; }
839	.pub-drill-title { font-size: 17px; font-weight: 600; letter-spacing: -0.3px; color: var(--color-ink); }
840	.pub-drill-sub { font-size: 12.5px; color: var(--st-muted); }
841	/* 카테고리 필터 칩 줄(기존 filter-pill 재사용, 간격만) */
842	.pub-cat-filters { display: flex; gap: 8px; flex-wrap: wrap; margin-bottom: 16px; }
843	
844	/* 미fetch 상태 안내(아직 가져오지 않음 — [새로고침]) */
845	.pub-empty-fetch {
846	  grid-column: 1 / -1; text-align: center; padding: 44px 20px;
847	  background: var(--color-canvas); border: 1px dashed var(--color-hairline); border-radius: var(--radius-lg);
848	}
